import React from 'react';
import NavBar from "./Components/NavBar";
import {Grid} from "@material-ui/core";

function App() {
  return (
    <React.Fragment>
    <NavBar />
  <Grid container>
    <Grid item sm>
    <h1> Hello </h1>
    </Grid>
    <Grid item sm>
      <h1> How are you?</h1>
    </Grid>
  </Grid>
    </React.Fragment>
  );
}

export default App;
